struct AnalyticsManager {
    static func logUserInteraction(userID: String, interactionType: String) {
        NSLog("User ID: \(userID), Interaction Type: \(interactionType)")
    }
    
    static func logAPICall(request: URLRequest, response: HTTPURLResponse, payload: Data) {
        NSLog("Request: \(request), Response: \(response), Payload: \(payload)")
    }
    
    static func logUserDataChange(userID: String, property: String, newValue: Any?) {
